        //ds_SeaImportContainerModify.UserStatus(ds_SeaImportContainerModify.RowPosition) = 2;
        if (ds_SeaImportContainerModify.getTotalRow() > 0) {
            for (var i = 0; i < ds_SeaImportContainerModify.getTotalRow(); i++) {
